import subprocess
import json
import sys
import pandas as pd
import re
from collections import Counter
import textwrap

import difflib

def remove_repeating_text(transcript, threshold=0.8):
    lines = transcript.split('\n')
    unique_lines = []

    for i, line1 in enumerate(lines):
        is_repeating = False
        for j, line2 in enumerate(lines):
            if i != j:
                # Calculate the similarity ratio between two lines
                similarity_ratio = difflib.SequenceMatcher(None, line1, line2).ratio()
                if similarity_ratio >= threshold:
                    is_repeating = True
                    break  # Line is repeating, break inner loop
        if not is_repeating:
            unique_lines.append(line1)

    cleaned_transcript = '\n'.join(unique_lines)
    return cleaned_transcript

output_excel = 'output.xlsx'

def merge():
    # Specify the file path
    file_path1 = 'word_dicts.json'
    file_path2 = 'speaker_dicts.json'

    # Open and load the JSON file
    with open(file_path1, 'r') as json_file:
        word_data = json.load(json_file)

    with open(file_path2, 'r') as json_file:
        speaker_data = json.load(json_file)

    s_data = pd.DataFrame(speaker_data)
    w_data = pd.DataFrame(word_data)

    # Create a DataFrame
    # df = pd.DataFrame(data)

    # Initialize variables
    merged_rows = []
    current_row = None

    # Iterate through the DataFrame
    for index, row in s_data.iterrows():
        if current_row is None:
            current_row = row
        elif row['speaker'] == current_row['speaker']:
            current_row['end'] = row['end']
        else:
            merged_rows.append(current_row)
            current_row = row

    # Append the last merged row
    if current_row is not None:
        merged_rows.append(current_row)

    # Create a new DataFrame with the merged rows
    merged_s_data = pd.DataFrame(merged_rows)

    # Define a function to find rows between closest_start_row and closest_end_row
    def find_rows_between(dataframe2, row_from_dataframe1):
        # Initialize variables to store the closest rows
        closest_start_row = None
        closest_end_row = None
        min_start_difference = float('inf')
        min_end_difference = float('inf')

        # Iterate through dataframe2 to find the closest start and end rows
        for index, row in dataframe2.iterrows():
            start_difference = abs(row_from_dataframe1['start'] - row['start'])
            end_difference = abs(row_from_dataframe1['end'] - row['end'])

            if start_difference < min_start_difference:
                min_start_difference = start_difference
                closest_start_row = row

            if end_difference < min_end_difference:
                min_end_difference = end_difference
                closest_end_row = row

        # Check if the word in closest_start_row is lowercase
        if closest_start_row['word'].islower():
            # Check if the previous row exists
            if closest_start_row.name > 0:
                previous_row = dataframe2.iloc[closest_start_row.name - 1]
                # Check if the word in the previous row is title case
                if previous_row['word'].istitle():
                    closest_start_row = previous_row

        # Find the index of closest_start_row and closest_end_row
        start_index = dataframe2.index.get_loc(closest_start_row.name)
        end_index = dataframe2.index.get_loc(closest_end_row.name)

        # Get all rows between and including closest_start_row and closest_end_row
        selected_rows = dataframe2.iloc[start_index:end_index + 1]

        return selected_rows

    conversation = ''
    conversation2 = ''
    # Iterate through rows in dataframe1 and call the function for each row
    for index, row in merged_s_data.iterrows():
        selected_rows = find_rows_between(w_data, row)
        conversation += f"\n\n\n\n{row['speaker']}  start:: [{row['start']}] ... end:: [{row['end']}]\n\n"
        sentence = ' '.join(selected_rows['word'])
        conversation += sentence
        conversation2 += sentence

    # Specify the file path where you want to save the Excel file
    file_path = "output.xlsx"

    # Write the DataFrame to an Excel file
    merged_s_data.to_excel(file_path, index=False)
    print(f"Data saved to {file_path}")

    threshold = 0.8
    cleaned_transcript = remove_repeating_text(conversation2, threshold)

    # print(cleaned_transcript)

    # Specify the file path where you want to save the text file
    file_path = "output.txt"

    # Open the file in write mode ('w') and write the text to it
    with open(file_path, 'w') as file:
        file.write(cleaned_transcript)

    print(f"Text saved to {file_path}")


if __name__ == "__main__":
    merge()

